1	import { useState, useEffect, useCallback } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export interface AppNotification {
5	  id: string;
6	  type: string;
7	  title: string;
8	  body: string | null;
9	  data: Record<string, string> | null;
10	  read: boolean;
11	  created_at: string;
12	}
13	
14	const LIMIT = 40;
15	const clearedKey = (uid: string) => `crevia_notif_cleared_${uid}`;
16	
17	function getClearedAt(userId: string): string | null {
18	  return localStorage.getItem(clearedKey(userId));
19	}
20	
21	function applyFilter(data: AppNotification[], userId: string): AppNotification[] {
22	  const clearedAt = getClearedAt(userId);
23	  if (!clearedAt) return data;
24	  return data.filter((n) => n.created_at > clearedAt);
25	}
26	
27	export function useNotifications(userId: string) {
28	  const [notifications, setNotifications] = useState<AppNotification[]>([]);
29	  const [loading, setLoading] = useState(false);
30	
31	  const refresh = useCallback(async () => {
32	    if (!userId) return;
33	    setLoading(true);
34	    try {
35	      const { data, error } = await supabase
36	        .from("notifications")
37	        .select("id, type, title, body, data, read, created_at")
38	        .eq("user_id", userId)
39	        .order("created_at", { ascending: false })
40	        .limit(LIMIT);
41	
42	      if (error) {
43	        console.error("[notifications] Failed to load:", error.message);
44	        return;
45	      }
46	
47	      setNotifications(applyFilter((data as AppNotification[]) ?? [], userId));
48	    } finally {
49	      setLoading(false);
50	    }
51	  }, [userId]);
52	
53	  useEffect(() => {
54	    if (!userId) return;
55	    refresh();
56	
57	    const handleCleared = () => setNotifications([]);
58	    window.addEventListener("crevia:notifications-cleared", handleCleared);
59	
60	    const channel = supabase
61	      .channel(`notifications:${userId}`)
62	      .on(
63	        "postgres_changes",
64	        { event: "INSERT", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
65	        (payload) => {
66	          const notif = payload.new as AppNotification;
67	          const clearedAt = getClearedAt(userId);
68	          if (clearedAt && notif.created_at <= clearedAt) return;
69	          setNotifications((prev) => [notif, ...prev].slice(0, LIMIT));
70	        }
71	      )
72	      .on(
73	        "postgres_changes",
74	        { event: "UPDATE", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
75	        (payload) => {
76	          const updated = payload.new as AppNotification;
77	          setNotifications((prev) => {
78	            const without = prev.filter((n) => n.id !== updated.id);
79	            return [updated, ...without].slice(0, LIMIT);
80	          });
81	        }
82	      )
83	      .on(
84	        "postgres_changes",
85	        { event: "DELETE", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
86	        (payload) => {
87	          const deleted = payload.old as { id: string };
88	          setNotifications((prev) => prev.filter((n) => n.id !== deleted.id));
89	        }
90	      )
91	      .subscribe();
92	
93	    return () => {
94	      supabase.removeChannel(channel);
95	      window.removeEventListener("crevia:notifications-cleared", handleCleared);
96	    };
97	  }, [userId, refresh]);
98	
99	  const markRead = useCallback(async (id: string) => {
100	    // Optimistic update first for instant feel
101	    setNotifications((prev) => prev.map((n) => (n.id === id ? { ...n, read: true } : n)));
102	    const { error } = await supabase.from("notifications").update({ read: true }).eq("id", id);
103	    if (error) {
104	      console.error("[notifications] Failed to mark read:", error.message);
105	      // Revert on failure
106	      setNotifications((prev) => prev.map((n) => (n.id === id ? { ...n, read: false } : n)));
107	    }
108	  }, []);
109	
110	  const markAllRead = useCallback(async () => {
111	    if (!userId) return;
112	    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
113	    const { error } = await supabase
114	      .from("notifications")
115	      .update({ read: true })
116	      .eq("user_id", userId)
117	      .eq("read", false);
118	    if (error) {
119	      console.error("[notifications] Failed to mark all read:", error.message);
120	      refresh();
121	    }
122	  }, [userId, refresh]);
123	
124	  const clearAll = useCallback(async () => {
125	    if (!userId) return;
126	    localStorage.setItem(clearedKey(userId), new Date().toISOString());
127	    window.dispatchEvent(new Event("crevia:notifications-cleared"));
128	    const { error } = await supabase.from("notifications").delete().eq("user_id", userId);
129	    if (error) {
130	      console.error("[notifications] Failed to clear:", error.message);
131	    }
132	  }, [userId]);
133	
134	  const unreadCount = notifications.filter((n) => !n.read).length;
135	
136	  return { notifications, unreadCount, loading, markRead, markAllRead, clearAll, refresh };
137	}
