1	import { useState } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
4	import { Button } from "@/components/ui/button";
5	import { ScrollArea } from "@/components/ui/scroll-area";
6	import { Bell, MessageSquare, FileSignature, Receipt, Sparkles, CreditCard, CheckCheck, Loader2, Trash2, AlertTriangle } from "lucide-react";
7	import { cn } from "@/lib/utils";
8	import type { AppNotification } from "@/hooks/use-notifications";
9	import { useToast } from "@/hooks/use-toast";
10	import {
11	  Dialog,
12	  DialogContent,
13	  DialogHeader,
14	  DialogTitle,
15	  DialogDescription,
16	  DialogFooter,
17	} from "@/components/ui/dialog";
18	
19	interface NotificationSheetProps {
20	  open: boolean;
21	  onOpenChange: (open: boolean) => void;
22	  notifications: AppNotification[];
23	  unreadCount: number;
24	  loading: boolean;
25	  onMarkRead: (id: string) => void;
26	  onMarkAllRead: () => void;
27	  onClearAll?: () => Promise<void>;
28	}
29	
30	function timeAgo(dateStr: string): string {
31	  const diff = Date.now() - new Date(dateStr).getTime();
32	  const mins = Math.floor(diff / 60000);
33	  if (mins < 1) return "just now";
34	  if (mins < 60) return `${mins}m ago`;
35	  const hrs = Math.floor(mins / 60);
36	  if (hrs < 24) return `${hrs}h ago`;
37	  const days = Math.floor(hrs / 24);
38	  if (days < 7) return `${days}d ago`;
39	  return new Date(dateStr).toLocaleDateString();
40	}
41	
42	const TYPE_CONFIG: Record<string, { icon: React.ElementType; color: string; nav: string }> = {
43	  message:  { icon: MessageSquare,  color: "text-blue-500",   nav: "/crevia-studio?tab=chat" },
44	  contract: { icon: FileSignature,  color: "text-bronze",     nav: "/crevia-studio?tab=contracts" },
45	  invoice:  { icon: Receipt,        color: "text-green-500",  nav: "/crevia-studio?tab=invoices" },
46	  campaign: { icon: Sparkles,       color: "text-purple-500", nav: "/crevia-studio" },
47	  billing:  { icon: CreditCard,     color: "text-orange-500", nav: "/profile/payments-billing" },
48	  system:   { icon: Bell,           color: "text-muted-foreground", nav: "" },
49	};
50	
51	export default function NotificationSheet({
52	  open,
53	  onOpenChange,
54	  notifications,
55	  unreadCount,
56	  loading,
57	  onMarkRead,
58	  onMarkAllRead,
59	  onClearAll,
60	}: NotificationSheetProps) {
61	  const navigate = useNavigate();
62	  const { toast } = useToast();
63	  const [clearDialogOpen, setClearDialogOpen] = useState(false);
64	  const [clearing, setClearing] = useState(false);
65	
66	  const handleClearAll = async () => {
67	    setClearing(true);
68	    try {
69	      await onClearAll?.();
70	      setClearDialogOpen(false);
71	    } catch (err: any) {
72	      toast({ title: "Failed to clear notifications", description: err.message, variant: "destructive" });
73	    } finally {
74	      setClearing(false);
75	    }
76	  };
77	
78	  const handleClick = (n: AppNotification) => {
79	    if (!n.read) onMarkRead(n.id);
80	    const cfg = TYPE_CONFIG[n.type] ?? TYPE_CONFIG.system;
81	    let nav = cfg.nav;
82	    if (n.type === "message" && n.data?.room_id) {
83	      nav = `/crevia-studio?tab=chat&roomId=${n.data.room_id}`;
84	    }
85	    if (nav) {
86	      navigate(nav);
87	      onOpenChange(false);
88	    }
89	  };
90	
91	  return (
92	    <Sheet open={open} onOpenChange={onOpenChange}>
93	      <SheetContent side="right" className="w-full sm:w-[380px] p-0 flex flex-col bg-background border-border">
94	        <SheetHeader className="px-4 pt-4 pb-3 border-b border-border flex-shrink-0">
95	          <div className="flex items-center justify-between">
96	            <SheetTitle className="font-vollkorn text-lg">Notifications</SheetTitle>
97	            {unreadCount > 0 && (
98	              <Button
99	                variant="ghost"
100	                size="sm"
101	                className="h-7 text-xs text-bronze hover:text-bronze/80 gap-1.5"
102	                onClick={onMarkAllRead}
103	              >
104	                <CheckCheck className="w-3.5 h-3.5" />
105	                Mark all read
106	              </Button>
107	            )}
108	          </div>
109	        </SheetHeader>
110	
111	        <ScrollArea className="flex-1">
112	          {loading ? (
113	            <div className="flex items-center justify-center py-16">
114	              <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
115	            </div>
116	          ) : notifications.length === 0 ? (
117	            <div className="flex flex-col items-center justify-center py-16 px-6 text-center">
118	              <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center mb-3">
119	                <Bell className="w-5 h-5 text-muted-foreground" />
120	              </div>
121	              <p className="font-poppins text-sm font-medium text-foreground mb-1">All caught up</p>
122	              <p className="text-xs text-muted-foreground">New messages and updates will appear here</p>
123	            </div>
124	          ) : (
125	            <div className="divide-y divide-border/50">
126	              {notifications.map((n) => {
127	                const cfg = TYPE_CONFIG[n.type] ?? TYPE_CONFIG.system;
128	                const Icon = cfg.icon;
129	                return (
130	                  <button
131	                    key={n.id}
132	                    onClick={() => handleClick(n)}
133	                    className={cn(
134	                      "w-full flex items-start gap-3 px-4 py-3.5 text-left transition-colors hover:bg-muted/50",
135	                      !n.read && "bg-bronze/5"
136	                    )}
137	                  >
138	                    <div className={cn("mt-0.5 p-2 rounded-lg flex-shrink-0", !n.read ? "bg-bronze/10" : "bg-muted")}>
139	                      <Icon className={cn("w-3.5 h-3.5", !n.read ? cfg.color : "text-muted-foreground")} />
140	                    </div>
141	                    <div className="flex-1 min-w-0">
142	                      <div className="flex items-start justify-between gap-2">
143	                        <p className={cn("text-sm leading-snug", !n.read ? "font-semibold text-foreground" : "font-medium text-foreground/80")}>
144	                          {n.title}
145	                        </p>
146	                        {!n.read && (
147	                          <span className="mt-1 w-2 h-2 rounded-full bg-bronze flex-shrink-0" />
148	                        )}
149	                      </div>
150	                      {n.body && (
151	                        <p className="text-xs text-muted-foreground mt-0.5 line-clamp-2">
152	                          {n.body === "🔒 Encrypted message" ? "Tap to open conversation" : n.body}
153	                        </p>
154	                      )}
155	                      <p className="text-[10px] text-muted-foreground/60 mt-1">{timeAgo(n.created_at)}</p>
156	                    </div>
157	                  </button>
158	                );
159	              })}
160	            </div>
161	          )}
162	        </ScrollArea>
163	
164	        <div className="px-4 py-3 border-t border-border flex-shrink-0 space-y-1">
165	          {notifications.length > 0 && (
166	            <Button
167	              variant="ghost"
168	              size="sm"
169	              className="w-full text-xs text-muted-foreground"
170	              onClick={() => { navigate("/profile/notifications"); onOpenChange(false); }}
171	            >
172	              Notification settings
173	            </Button>
174	          )}
175	          {notifications.length > 0 && (
176	            <Button
177	              variant="ghost"
178	              size="sm"
179	              className="w-full text-xs text-muted-foreground hover:text-destructive hover:bg-destructive/10 gap-1.5"
180	              onClick={() => setClearDialogOpen(true)}
181	            >
182	              <Trash2 className="w-3.5 h-3.5" />
183	              Clear All Notifications
184	            </Button>
185	          )}
186	        </div>
187	      </SheetContent>
188	
189	      <Dialog open={clearDialogOpen} onOpenChange={setClearDialogOpen}>
190	        <DialogContent>
191	          <DialogHeader>
192	            <DialogTitle className="flex items-center gap-2">
193	              <AlertTriangle className="w-5 h-5 text-destructive" />
194	              Clear All Notifications?
195	            </DialogTitle>
196	            <DialogDescription>
197	              This will permanently remove all your notifications. This cannot be undone.
198	            </DialogDescription>
199	          </DialogHeader>
200	          <DialogFooter className="gap-2 sm:gap-0">
201	            <Button variant="ghost" onClick={() => setClearDialogOpen(false)}>
202	              Cancel
203	            </Button>
204	            <Button variant="destructive" onClick={handleClearAll} disabled={clearing}>
205	              {clearing ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
206	              {clearing ? "Clearing..." : "Clear All"}
207	            </Button>
208	          </DialogFooter>
209	        </DialogContent>
210	      </Dialog>
211	    </Sheet>
212	  );
213	}
