1	import { useState, useEffect } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { Card } from "@/components/ui/card";
4	import { Switch } from "@/components/ui/switch";
5	import { Label } from "@/components/ui/label";
6	import { Button } from "@/components/ui/button";
7	import { supabase } from "@/integrations/supabase/client";
8	import { useNotifications } from "@/hooks/use-notifications";
9	import { Bell, MessageSquare, FileText, Sparkles, Shield, BellOff, CheckCheck, Loader2, MessageCircle, FileSignature, Receipt } from "lucide-react";
10	import { cn } from "@/lib/utils";
11	const SETTINGS_KEY = "crevia_notif_settings";
12	
13	const notificationGroups = [
14	  {
15	    title: "Crevia Studio",
16	    items: [
17	      { id: "chat",     icon: MessageSquare, label: "Chat Messages",        desc: "New messages in Crevia Chat" },
18	      { id: "invoices", icon: FileText,      label: "Invoices & Canvas", desc: "Status updates on invoices and Canvas" },
19	    ],
20	  },
21	  {
22	    title: "Kira AI",
23	    items: [
24	      { id: "kira", icon: Sparkles, label: "Kira Suggestions", desc: "AI-powered tips and recommendations" },
25	    ],
26	  },
27	  {
28	    title: "Account",
29	    items: [
30	      { id: "billing",  icon: Bell,       label: "Billing & Subscription", desc: "Payment confirmations and plan changes" },
31	      { id: "security", icon: Shield,     label: "Security Alerts",        desc: "Login activity and password changes" },
32	    ],
33	  },
34	];
35	
36	const TYPE_CONFIG: Record<string, { icon: React.ElementType; nav: string }> = {
37	  message:  { icon: MessageCircle, nav: "/crevia-studio?tab=chat" },
38	  contract: { icon: FileSignature, nav: "/crevia-studio?tab=contracts" },
39	  invoice:  { icon: Receipt,       nav: "/crevia-studio?tab=invoices" },
40	  campaign: { icon: Sparkles,      nav: "/crevia-studio" },
41	  billing:  { icon: Bell,          nav: "/profile/payments-billing" },
42	  system:   { icon: Bell,          nav: "" },
43	};
44	
45	function timeAgo(dateStr: string): string {
46	  const diff = Date.now() - new Date(dateStr).getTime();
47	  const mins = Math.floor(diff / 60000);
48	  if (mins < 1) return "just now";
49	  if (mins < 60) return `${mins}m ago`;
50	  const hrs = Math.floor(mins / 60);
51	  if (hrs < 24) return `${hrs}h ago`;
52	  return `${Math.floor(hrs / 24)}d ago`;
53	}
54	
55	const Notifications = () => {
56	  const navigate = useNavigate();
57	  const [userId, setUserId] = useState("");
58	  const [activeId, setActiveId] = useState<string | null>(null);
59	  const [settings, setSettings] = useState<Record<string, boolean>>(() => {
60	    try {
61	      const saved = localStorage.getItem(SETTINGS_KEY);
62	      return saved ? JSON.parse(saved) : { chat: true, invoices: true, kira: true, billing: true, security: true, muteAll: false };
63	    } catch {
64	      return { chat: true, invoices: true, kira: true, billing: true, security: true, muteAll: false };
65	    }
66	  });
67	
68	  const { notifications, unreadCount, loading, markAllRead, markRead } = useNotifications(userId);
69	
70	  useEffect(() => {
71	    // getSession for the immediate value, onAuthStateChange for reliability
72	    supabase.auth.getSession().then(({ data: { session } }) => {
73	      if (session) setUserId(session.user.id);
74	    });
75	    const { data: { subscription } } = supabase.auth.onAuthStateChange((_e, session) => {
76	      setUserId(session?.user?.id ?? "");
77	    });
78	    return () => subscription.unsubscribe();
79	  }, []);
80	
81	  const toggle = (id: string) => {
82	    setSettings(prev => {
83	      const next = { ...prev, [id]: !prev[id] };
84	      localStorage.setItem(SETTINGS_KEY, JSON.stringify(next));
85	      return next;
86	    });
87	  };
88	
89	  return (
90	    <div className="min-h-screen bg-background">
91	      <div className="container mx-auto px-4 md:px-6 py-8 md:py-12 max-w-2xl">
92	        <div className="flex items-center gap-3 mb-2">
93	          <Bell className="w-6 h-6 text-bronze" />
94	          <h1 className="font-vollkorn text-3xl md:text-4xl font-bold">Notifications</h1>
95	        </div>
96	        <p className="text-muted-foreground mb-8 text-sm">Manage alerts and see recent activity</p>
97	
98	        {/* Recent notifications — only shown when there are notifications */}
99	        {(loading || notifications.length > 0) && (
100	        <div className="mb-6">
101	          <div className="flex items-center justify-between mb-3">
102	            <h2 className="font-poppins text-xs font-semibold text-muted-foreground uppercase tracking-wider">
103	              Recent
104	              {unreadCount > 0 && (
105	                <span className="ml-2 px-1.5 py-0.5 rounded-full bg-bronze/10 text-bronze text-[10px]">
106	                  {unreadCount} unread
107	                </span>
108	              )}
109	            </h2>
110	            {unreadCount > 0 && (
111	              <Button variant="ghost" size="sm" className="h-7 text-xs text-bronze gap-1.5" onClick={markAllRead}>
112	                <CheckCheck className="w-3.5 h-3.5" /> Mark all read
113	              </Button>
114	            )}
115	          </div>
116	
117	          <Card className="overflow-hidden">
118	            {loading ? (
119	              <div className="flex items-center justify-center py-10">
120	                <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
121	              </div>
122	            ) : (
123	              <div className="divide-y divide-border/50">
124	                {notifications.slice(0, 10).map(n => {
125	                  const cfg = TYPE_CONFIG[n.type] ?? TYPE_CONFIG.system;
126	                  const Icon = cfg.icon;
127	                  const isActive = activeId === n.id;
128	                  return (
129	                    <div
130	                      key={n.id}
131	                      onClick={() => {
132	                        if (!n.read) markRead(n.id);
133	                        setActiveId(n.id);
134	                        let nav = cfg.nav;
135	                        if (n.type === "message" && n.data?.room_id) {
136	                          nav = `/crevia-studio?tab=chat&roomId=${n.data.room_id}`;
137	                        }
138	                        if (nav) navigate(nav);
139	                      }}
140	                      className={cn(
141	                        "flex items-start gap-3 px-4 py-3.5 cursor-pointer hover:bg-muted/40 transition-colors",
142	                        !n.read && "bg-bronze/5",
143	                        isActive && "bg-bronze/10 border-l-2 border-bronze"
144	                      )}
145	                    >
146	                      <div className={cn("mt-0.5 p-1.5 rounded-lg flex-shrink-0", !n.read || isActive ? "bg-bronze/10" : "bg-muted")}>
147	                        <Icon className={cn("w-3.5 h-3.5", !n.read || isActive ? "text-bronze" : "text-muted-foreground")} />
148	                      </div>
149	                      <div className="flex-1 min-w-0">
150	                        <div className="flex items-start justify-between gap-2">
151	                          <p className={cn("text-sm leading-snug", !n.read || isActive ? "font-semibold" : "font-medium text-foreground/80")}>
152	                            {n.title}
153	                          </p>
154	                          {!n.read && <span className="mt-1.5 w-2 h-2 rounded-full bg-bronze flex-shrink-0" />}
155	                        </div>
156	                        {n.body && <p className="text-xs text-muted-foreground mt-0.5 line-clamp-1">{n.body}</p>}
157	                        <p className="text-[10px] text-muted-foreground/50 mt-1">{timeAgo(n.created_at)}</p>
158	                      </div>
159	                    </div>
160	                  );
161	                })}
162	              </div>
163	            )}
164	          </Card>
165	        </div>
166	        )}
167	
168	        {/* Settings */}
169	        <h2 className="font-poppins text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">
170	          Preferences
171	        </h2>
172	
173	        {notificationGroups.map((group) => (
174	          <Card key={group.title} className="p-5 mb-4">
175	            <h3 className="font-vollkorn text-xs font-semibold mb-4 text-muted-foreground uppercase tracking-wide">
176	              {group.title}
177	            </h3>
178	            <div className="space-y-4">
179	              {group.items.map((item) => {
180	                const Icon = item.icon;
181	                return (
182	                  <div key={item.id} className="flex items-center justify-between">
183	                    <div className="flex items-center gap-3">
184	                      <Icon className="w-4 h-4 text-bronze shrink-0" />
185	                      <div>
186	                        <Label htmlFor={item.id} className="font-medium text-sm">{item.label}</Label>
187	                        <p className="text-xs text-muted-foreground">{item.desc}</p>
188	                      </div>
189	                    </div>
190	                    <Switch
191	                      id={item.id}
192	                      checked={!settings.muteAll && settings[item.id]}
193	                      disabled={settings.muteAll}
