141	// Proper URL detection without global regex issues
142	function linkifyContent(content: string): (string | JSX.Element)[] {
143	  const urlPattern = /(https?:\/\/[^\s<]+[^\s<.,;:!?"')\]])/g;
144	  const result: (string | JSX.Element)[] = [];
145	  let lastIndex = 0;
146	  let match: RegExpExecArray | null;
147	
148	  while ((match = urlPattern.exec(content)) !== null) {
149	    if (match.index > lastIndex) {
150	      result.push(content.slice(lastIndex, match.index));
151	    }
152	    const url = match[0];
153	    result.push(
154	      <a
155	        key={`link-${match.index}`}
156	        href={url}
157	        target="_blank"
158	        rel="noopener noreferrer"
159	        className="underline font-medium hover:opacity-80 break-all"
160	        onClick={(e) => e.stopPropagation()}
161	      >
162	        {url}
163	      </a>
164	    );
165	    lastIndex = match.index + url.length;
166	  }
167	
168	  if (lastIndex < content.length) {
169	    result.push(content.slice(lastIndex));
170	  }
171	
172	  return result.length > 0 ? result : [content];
173	}
