181	// Generates a unique, consistent hue-based color for each user (WhatsApp-style)
182	const avatarStyle = (seed: string): React.CSSProperties => {
183	  let hash = 0;
184	  for (let i = 0; i < seed.length; i++) {
185	    hash = seed.charCodeAt(i) + ((hash << 5) - hash);
186	  }
187	  const hue = Math.abs(hash) % 360;
188	  return { background: `hsl(${hue},55%,65%)`, color: `hsl(${hue},55%,22%)` };
189	};
