247	    async (plaintext: string, roomId: string): Promise<{ content: string; is_encrypted: boolean }> => {
248	      const members = selectedRoom?.members ?? [];
249	      const memberIds = members.map((m) => m.user_id);
250	
251	      // Verify every room member has a registered public key before encrypting.
252	      for (const memberId of memberIds) {
253	        const key = await getPublicKey(memberId);
254	        if (!key) {
255	          if (memberId === currentUserId) {
256	            // Own key is missing — re-run initialisation and block this send.
257	            initEncryption();
258	            throw new Error("Your encryption keys are being set up. Please try again in a moment.");
259	          }
260	          const profile = members.find((m) => m.user_id === memberId)?.profile;
261	          const name = profile?.display_name || profile?.handle || "A participant";
262	          throw new Error(`${name} hasn't set up encryption yet. Message not sent.`);
263	        }
264	      }
265	
266	      // Attempt encryption using the current user's copy of the room key.
267	      let encrypted = await encrypt(plaintext, roomId);
268	
269	      if (!encrypted) {
270	        // Before generating a new key, check if any key already exists for this
271	        // room. If it does, we must not generate a new one — that would make all
272	        // previously encrypted messages unreadable. Instead, the other participant
273	        // needs to redistribute their copy of the existing key to us.
274	        const { data: existingKeys } = await (supabase
275	          .from("room_encrypted_keys" as any)
276	          .select("id")
277	          .eq("room_id", roomId)
278	          .limit(1)) as { data: { id: string }[] | null };
279	
280	        if (existingKeys && existingKeys.length > 0) {
281	          // Key exists in the DB but not for the current user — ask the other
282	          // party to open the chat, which triggers redistribution via selectRoom.
283	          throw new Error(
284	            "Securing chat... The other person needs to open the chat once to sync your key. Then try again."
285	          );
286	        }
